import{_ as e,c as p,o as t,ae as o}from"./chunks/framework.BvcDoAct.js";const M=JSON.parse('{"title":"KAIRYU (MAZZEL)","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/12_KAIRYU.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/12_KAIRYU.md"}'),r={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/12_KAIRYU.md"};function n(i,a,l,I,A,S){return t(),p("div",null,[...a[0]||(a[0]=[o('<p>Talk about BMSG - 12</p><h1 id="kairyu-mazzel" tabindex="-1">KAIRYU (MAZZEL) <a class="header-anchor" href="#kairyu-mazzel" aria-label="Permalink to &quot;KAIRYU (MAZZEL)&quot;">​</a></h1><h3 id="「the-first」落选后经历烦恼与挣扎-并坚定地认为-无论如何都要加入bmsg" tabindex="-1">「THE FIRST」落选后经历烦恼与挣扎，并坚定地认为“无论如何都要加入BMSG” <a class="header-anchor" href="#「the-first」落选后经历烦恼与挣扎-并坚定地认为-无论如何都要加入bmsg" aria-label="Permalink to &quot;「THE FIRST」落选后经历烦恼与挣扎，并坚定地认为“无论如何都要加入BMSG”&quot;">​</a></h3><p><em>KAIRYU：2000年10月22日出生，兵库县出身</em></p><p><br><br><br> ————在参加「THE FIRST」之后主动联系SKY-HI并成为练习生的KAIRYU。你对BMSG的情感想必比任何人都更强烈，那么请再次谈谈你特别尊敬SKY-HI的地方？</p><p>虽然由我来说有些冒昧，但我认为他毫不夸张地说，是当今日本音乐界的异端，也是具有革命性的人物。即便是看似与他没有直接关系的事情，我在观察这个世界时也会想：“这绝对是因为社长当初做了那样的行动，才得以实现的吧。”那些大家都会觉得“如果能这样就好了”，但因为需要资金、人脉和勇气而无法付诸行动的事情，社长全都亲自实践过了。而这些最终也反过来成就了他自己。他是一个把说出口的话一一付诸实现的人，我觉得今后也会继续如此。能够在这样的人麾下活动让我感到自豪，而他那种极其强烈的进取心，也让我作为一个人由衷地敬佩。</p><h3 id="社长发来的第一条line是「welcome-to-tokio」" tabindex="-1">社长发来的第一条LINE是「Welcome to TOKIO」 <a class="header-anchor" href="#社长发来的第一条line是「welcome-to-tokio」" aria-label="Permalink to &quot;社长发来的第一条LINE是「Welcome to TOKIO」&quot;">​</a></h3><p>————在和SKY-HI交流的过程中，有没有让你印象特别深刻的话？</p><p>在「THE FIRST」落选、回到老家之后，我因为自尊和内心的挣扎，一直非常犹豫要不要联系社长。但最终还是因为“无论如何都想加入BMSG”的念头去联系了他。确定成为练习生、交换了LINE之后，社长发来的第一句话是“Welcome to TOKIO”。我当时就觉得：“太有SKY-HI风格了！”那正好是我来到东京、为实现持续追逐了七年的出道目标而终于进入真正起跑阶段的时刻，所以单纯地觉得“太帅了！”虽然心里也想过“不是TOKYO而是TOKIO啊”，但当时还没到可以吐槽的关系（笑）。</p><p>————后来有问过“为什么是TOKIO”吗？</p><p>现在久违地又想起来了，下次去问问看（笑）。那种说法一般人还真想不出来。他总是会说出那种没有亲身经历就说不出口的话，所以在这一点上我对他的尊敬也停不下来。</p><p>————顺便问一下，虽然SKY-HI给人的印象总是很积极，但在需要提醒或批评的时候，他是怎么传达的？</p><p>他不会单纯地发火，而是用一种自然就能让人绷紧神经的语气和措辞来表达。会让人不知不觉地产生“必须这样去改变”的想法。</p><p>————2024年MAZZEL迎来了首次巡演和Arena公演。作为团队，你们是否也切实感受到很大的成长？</p><p>我每次都会把整场演出的录像完整地回看。巡演的第一场和最终场，舞蹈和演唱完全不一样。我们不是单纯地完成了9场巡演，而是每结束一场，就会和演出团队一起进行复盘，社长也会在每个阶段给予建议。这样的积累越多，我就越能切实感受到自己的成长。</p><p>————KAIRYU作为MAZZEL在声乐方面的核心人物，也会有意识地去提升成员整体的歌唱实力吗？</p><p>我也不确定自己到底帮上了多少忙……但在录音或现场演出中，只要有注意到的地方，就会告诉大家“这样唱会更好”。在MAZZEL的魅力当中，我非常希望我们一定要具备“唱功出色的团队”这一点。大家各自的强项不同，但在唱歌方面，我能感受到成员们对我的信任，同时也有成员会反过来说“这里是不是可以这样”。我们是在平等地互相给建议。我不希望听起来像居高临下，但我真的觉得大家都变得更厉害了，同时我也被大家带动，感觉自己的歌唱能力也在提升，形成了一个很好的正向循环。</p><p>————第一次站上Arena单独公演时的景象如何？</p><p>能够站上Arena本身，我就觉得是成长的证明。出道仅一年半就进行4场Arena公演，这种情况其实不太常见。虽然觉得如果我们这些还算新人能够成功完成，一定会更有自信，但多少还是有些不安。不过在首日真正站上舞台时，安心感和自信就涌了上来。现场的所有人都是MUZE（MAZZEL粉丝名），那真的是非常震撼的景象，也让我切身感受到“这样的支持绝不是理所当然的”。我深刻意识到，是社长和MUZE让我们获得了自信。</p><p>————关于今后的MAZZEL，你和SKY-HI有过怎样的交流？</p><p>发行了专辑、完成了巡演，这次发布的单曲《MAZQUERADE》我觉得算是一个阶段性的节点。到目前为止，是一个把社长想展现的MAZZEL的优势全部释放出来的阶段。接下来如果说是“第二章”可能有点夸张，但我能从社长的言谈之间感受到，他在思考接下来要推出怎样的歌曲、要以什么方式去进攻市场，这是一个面向明年的非常重要的时期。每一次这样的交流都让我觉得非常可靠，也让我更加期待未来。</p><p>————随着BMSG本部大楼建成，艺人之间的交流似乎也更频繁了。KAIRYU平时是怎样沟通的？</p><p>我大概是公司里最少使用桑拿的艺人之一（笑）。不过随着大楼建成，确实比以前更容易和其他艺人交流了。前阵子我还在艺人室和练习生一起见面，玩了《马里奥赛车》（笑）。这种轻松的交流方式，可能也只有在BMSG才比较常见吧。即使不是我亲自参与，也会经常听成员说“前几天和谁谁聊了”，因此也会产生更多亲近感。既然在同一家公司，距离越近越好，我也能感受到，大楼的建成正在让社长想实现的东西一步步变成现实。</p><p>————9月举办的「BMSG FES&#39;24」汇聚了所有BMSG艺人，有什么让你印象深刻的地方？</p><p>我既是BMSG的一员，同时也是BMSG的超级粉丝。BE:FIRST今年依然很厉害，而edhiii boi的成长更是让我感到震撼……大家无论是舞台表现、MC、歌唱还是舞蹈都非常出色，我完全是以粉丝的视角去亲眼见证，并不断受到冲击。同时我也觉得，在BMSG当中MAZZEL所承担的角色非常重要，这三天对我来说是一次非常好的刺激。</p><h3 id="这样-讲究帅气-的公司真的不多见" tabindex="-1">这样“讲究帅气”的公司真的不多见 <a class="header-anchor" href="#这样-讲究帅气-的公司真的不多见" aria-label="Permalink to &quot;这样“讲究帅气”的公司真的不多见&quot;">​</a></h3><p>————和从「THE FIRST」时期就认识的REIKO一起演唱了《ICE》。</p><p>小玲（REIKO）是最尊重我歌声的人，我也非常尊敬她。BMSG的成员每个人声音都很好听、唱功也都很强，但在唱法和喜欢的音乐上，她是和我最相似的一个，所以一直以来我都很希望能和她一起站上舞台。那是一种和在MAZZEL时完全不同的高涨感，而且这是建立在我们一起度过练习生时期的故事之上的舞台，我也看到了有观众流下眼泪。这是今年音乐节中让我印象特别深刻的一场演出。</p><p>————作为BMSG的一员，如果要重新用语言表达你引以为傲的地方，会是什么？</p><p>我这个人有点爱耍帅，可以说是那种“始终想保持自己觉得很帅的状态”的人。我觉得这一点和社长非常相似。我认为像这样如此“讲究帅气”的公司真的很少见。不只是看利益，而是也会认真考虑在大众眼中的形象，这一点让我非常有共鸣。我希望这家公司能够一直保持这样的风格。</p><p>————2025年在经历「THE LAST PIECE」之后，BMSG的第三个组合将会诞生。</p><p>光是看RUI、TAIKI、KANON，就可以确信会诞生一个与BE:FIRST以及我们都不同的组合。各种风格完全不同的组合在各自领域产生影响，也会让社长的理想一步步实现。我们也会在其中，切实完成社长对MAZZEL的期待。首先是朝着未来一两年的目标，持续不断地努力。</p><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>其实这点我也和他说过，他是最接近我在AAA时期心态的人。虽然在歌唱实力上他远远在我之上（笑）。不过说到Rap和词曲创作，目前还是我更强（笑）！！在此基础上，他既有很高的自我要求和社会性，也有广阔的视野，同时还带着锋芒……让我不止一次地觉得“啊，要是能和KAIRYU这样的人作为成员一起活动就好了”。</p><p>也许有人会觉得他是偏匠人气质的歌手，但其实他是那种非常擅长将情感具象化的艺术家。不仅仅是实现自己的梦想，他对“与他人一起实现梦想”也有很强的动力，所以无论发生什么他都会成功。而且我也差不多该和他一起做首歌了，就拜托了（笑）。</p></blockquote>',33)])])}const h=e(r,[["render",n]]);export{M as __pageData,h as default};
